import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Button,
  Typography,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  Chip,
  Stack,
  Alert,
  Snackbar,
  CircularProgress,
  LinearProgress,
  useTheme,
  FormControlLabel,
  Switch,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
  FormHelperText,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  DarkMode as DarkModeIcon,
  LightMode as LightModeIcon,
  OpenInNew as OpenInNewIcon,
  Sync as SyncIcon,
  CloudSync as CloudSyncIcon
} from '@mui/icons-material';
import { motion } from 'framer-motion';
import { getNodes, getNodeGroups, createNodeGroup, updateNodeGroup, deleteNodeGroup, importNodes } from '../services/api';
import { getCommonStyles } from '../styles/commonStyles';

const Nodes = ({ mode, setMode, onDashboardClick }) => {
  const theme = useTheme();
  const styles = getCommonStyles(theme);
  const [nodes, setNodes] = useState([]);
  const [nodeGroups, setNodeGroups] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [openGroupDialog, setOpenGroupDialog] = useState(false);
  const [selectedGroup, setSelectedGroup] = useState(null);
  const [editGroup, setEditGroup] = useState({
    name: '',
    tag: '',
    includePatterns: [],
    excludePatterns: [],
    mode: 'select',
    active: true
  });
  const [openNodeDialog, setOpenNodeDialog] = useState(false);
  const [selectedNode, setSelectedNode] = useState(null);
  const [editNode, setEditNode] = useState({
    name: '',
    type: 'ss',
    server: '',
    port: '',
    password: '',
    uuid: ''
  });
  const [openImportDialog, setOpenImportDialog] = useState(false);
  const [importUrl, setImportUrl] = useState('');
  const [autoUpdate, setAutoUpdate] = useState(false);
  const [updateInterval, setUpdateInterval] = useState('');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [nodesData, groupsData] = await Promise.all([
        getNodes(),
        getNodeGroups()
      ]);
      setNodes(nodesData);
      setNodeGroups(groupsData);
      setError(null);
    } catch (err) {
      setError(err.response?.data?.error || '获取数据失败');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenGroupDialog = (group = null) => {
    if (group) {
      setSelectedGroup(group);
      setEditGroup({
        ...group,
        includePatterns: group.includePatterns || [],
        excludePatterns: group.excludePatterns || [],
        mode: group.mode || 'select',
        tag: group.tag || '',
        active: group.active ?? true
      });
    } else {
      setSelectedGroup(null);
      setEditGroup({
        name: '',
        tag: '',
        includePatterns: [],
        excludePatterns: [],
        mode: 'select',
        active: true
      });
    }
    setOpenGroupDialog(true);
  };

  const handleCloseGroupDialog = () => {
    setOpenGroupDialog(false);
    setSelectedGroup(null);
    setEditGroup({
      name: '',
      tag: '',
      includePatterns: [],
      excludePatterns: [],
      mode: 'select',
      active: true
    });
  };

  const handleSaveGroup = async () => {
    try {
      setLoading(true);
      if (selectedGroup) {
        await updateNodeGroup(selectedGroup.id, editGroup);
      } else {
        await createNodeGroup(editGroup);
      }
      await fetchData();
      setSuccess(true);
      handleCloseGroupDialog();
    } catch (err) {
      setError(err.response?.data?.error || '保存分组失败');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteGroup = async (id) => {
    try {
      setLoading(true);
      await deleteNodeGroup(id);
      await fetchData();
      setSuccess(true);
    } catch (err) {
      setError(err.response?.data?.error || '删除分组失败');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenNodeDialog = (node = null) => {
    if (node) {
      setSelectedNode(node);
      setEditNode({
        ...node,
        name: node.name || '',
        type: node.type || 'ss',
        server: node.server || '',
        port: node.port || '',
        password: node.password || '',
        uuid: node.uuid || ''
      });
    } else {
      setSelectedNode(null);
      setEditNode({
        name: '',
        type: 'ss',
        server: '',
        port: '',
        password: '',
        uuid: ''
      });
    }
    setOpenNodeDialog(true);
  };

  const handleCloseNodeDialog = () => {
    setOpenNodeDialog(false);
    setSelectedNode(null);
    setEditNode({
      name: '',
      type: 'ss',
      server: '',
      port: '',
      password: '',
      uuid: ''
    });
  };

  const handleSaveNode = async () => {
    try {
      setLoading(true);
      if (selectedNode) {
        await updateNodeGroup(selectedNode.id, editNode);
      } else {
        await createNodeGroup(editNode);
      }
      await fetchData();
      setSuccess(true);
      handleCloseNodeDialog();
    } catch (err) {
      setError(err.response?.data?.error || '保存节点失败');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenImportDialog = () => {
    setOpenImportDialog(true);
  };

  const handleCloseImportDialog = () => {
    setOpenImportDialog(false);
    setImportUrl('');
    setAutoUpdate(false);
    setUpdateInterval('');
  };

  const handleImportNodes = async () => {
    try {
      setLoading(true);
      await importNodes(importUrl, autoUpdate, parseInt(updateInterval));
      await fetchData();
      setSuccess(true);
      handleCloseImportDialog();
    } catch (err) {
      setError(err.response?.data?.error || '导入节点失败');
    } finally {
      setLoading(false);
    }
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: {
        duration: 0.3,
      }
    }
  };

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.1
      }
    }
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card sx={styles.headerCard}>
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" justifyContent="space-between">
            <Stack direction="row" alignItems="center" spacing={2}>
              <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
                节点管理
              </Typography>
              {loading && (
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
                </Box>
              )}
            </Stack>
            <Stack direction="row" spacing={1}>
              <IconButton
                size="small"
                onClick={onDashboardClick}
                sx={styles.iconButton}
              >
                <OpenInNewIcon fontSize="small" />
              </IconButton>
              <IconButton
                size="small"
                onClick={() => setMode(mode === 'dark' ? 'light' : 'dark')}
                sx={styles.iconButton}
              >
                {mode === 'dark' ? <LightModeIcon fontSize="small" /> : <DarkModeIcon fontSize="small" />}
              </IconButton>
            </Stack>
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      {/* Nodes List */}
      <Box sx={{ mb: 3 }}>
        <Box sx={{ mb: 2, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Typography variant="h6">节点列表</Typography>
          <Stack direction="row" spacing={1}>
            <Button
              variant="contained"
              size="small"
              startIcon={<AddIcon />}
              onClick={() => handleOpenNodeDialog()}
              sx={styles.actionButton}
            >
              添加节点
            </Button>
            <Button
              variant="contained"
              size="small"
              startIcon={<CloudSyncIcon />}
              onClick={() => handleOpenImportDialog()}
              sx={styles.actionButton}
            >
              导入节点
            </Button>
            <Button
              variant="contained"
              size="small"
              startIcon={<SyncIcon />}
              onClick={fetchData}
              disabled={loading}
              sx={styles.actionButton}
            >
              刷新节点
            </Button>
          </Stack>
        </Box>
        <TableContainer component={Paper} sx={styles.tableContainer}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell>名称</TableCell>
                <TableCell>类型</TableCell>
                <TableCell>地址</TableCell>
                <TableCell>延迟</TableCell>
                <TableCell>状态</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {nodes.map((node) => (
                <TableRow key={node.id}>
                  <TableCell>{node.name}</TableCell>
                  <TableCell>{node.type}</TableCell>
                  <TableCell>{node.address}</TableCell>
                  <TableCell>{node.latency}ms</TableCell>
                  <TableCell>
                    <Chip 
                      label={node.status} 
                      size="small"
                      sx={node.status === 'online' ? styles.chip.success : styles.chip.error}
                    />
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </TableContainer>
      </Box>

      {/* Node Groups */}
      <Box sx={{ mb: 2, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Typography variant="h6">节点分组</Typography>
        <Button
          variant="contained"
          size="small"
          startIcon={<AddIcon />}
          onClick={() => handleOpenGroupDialog()}
          sx={styles.actionButton}
        >
          添加分组
        </Button>
      </Box>

      <Grid container spacing={1.5}>
        {nodeGroups.map((group) => (
          <Grid item xs={12} sm={6} md={3} key={group.id}>
            <Card sx={styles.card}>
              <CardContent>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
                  <Stack direction="row" spacing={1} alignItems="center">
                    <Chip 
                      label={group.tag} 
                      size="small"
                      sx={styles.chip.primary}
                    />
                    <Typography variant="h6">{group.name}</Typography>
                  </Stack>
                  <Stack direction="row" spacing={0.5}>
                    <IconButton 
                      size="small" 
                      onClick={() => handleOpenGroupDialog(group)}
                      sx={{
                        color: 'text.secondary',
                        '&:hover': {
                          color: 'primary.main',
                          backgroundColor: 'action.hover',
                        },
                      }}
                    >
                      <EditIcon fontSize="small" />
                    </IconButton>
                    <IconButton 
                      size="small" 
                      onClick={() => handleDeleteGroup(group.id)}
                      sx={{
                        color: 'text.secondary',
                        '&:hover': {
                          color: 'error.main',
                          backgroundColor: 'action.hover',
                        },
                      }}
                    >
                      <DeleteIcon fontSize="small" />
                    </IconButton>
                  </Stack>
                </Box>
                <Stack direction="row" spacing={1} alignItems="center">
                  <Typography variant="body2" color="text.secondary">
                    {group.nodeCount || 0} 个节点
                  </Typography>
                  <Chip 
                    label={group.active ? "活跃" : "未激活"} 
                    size="small"
                    sx={group.active ? styles.chip.success : styles.chip.error}
                  />
                  <Chip 
                    label={group.mode === 'select' ? "手动选择" : "自动测速"} 
                    size="small"
                    sx={group.mode === 'select' ? styles.chip.warning : styles.chip.success}
                  />
                </Stack>
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      {/* Group Dialog */}
      <Dialog 
        open={openGroupDialog} 
        onClose={handleCloseGroupDialog} 
        maxWidth="sm" 
        fullWidth
        PaperProps={{
          sx: styles.dialog
        }}
      >
        <DialogTitle>
          {selectedGroup ? '编辑分组' : '添加分组'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="分组名称"
                  value={editGroup.name}
                  onChange={(e) => setEditGroup({ ...editGroup, name: e.target.value })}
                  size="small"
                  sx={styles.textField}
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="分组标签"
                  value={editGroup.tag}
                  onChange={(e) => setEditGroup({ ...editGroup, tag: e.target.value })}
                  size="small"
                  placeholder="例如：HK, JP, SG, US"
                  sx={styles.textField}
                />
              </Grid>
              <Grid item xs={12}>
                <FormControl fullWidth size="small">
                  <InputLabel>节点选择模式</InputLabel>
                  <Select
                    value={editGroup.mode}
                    label="节点选择模式"
                    onChange={(e) => setEditGroup({ ...editGroup, mode: e.target.value })}
                    sx={styles.textField}
                  >
                    <MenuItem value="select">手动选择</MenuItem>
                    <MenuItem value="urltest">自动测速</MenuItem>
                  </Select>
                  <FormHelperText>
                    {editGroup.mode === 'select' ? '手动选择节点' : '自动选择可用和延迟较低的节点'}
                  </FormHelperText>
                </FormControl>
              </Grid>
              <Grid item xs={12}>
                <FormControlLabel
                  control={
                    <Switch
                      checked={editGroup.active}
                      onChange={(e) => setEditGroup({ ...editGroup, active: e.target.checked })}
                    />
                  }
                  label="活跃"
                />
              </Grid>
              <Grid item xs={12}>
                <Typography variant="subtitle2" gutterBottom>
                  节点匹配规则
                </Typography>
                <Stack spacing={2}>
                  <Box>
                    <Typography variant="body2" color="text.secondary" gutterBottom>
                      包含节点（白名单模式）
                    </Typography>
                    <TextField
                      fullWidth
                      multiline
                      rows={3}
                      placeholder="每行一个正则表达式，例如：
香港|HK|🇭🇰
新加坡|SG|🇸🇬
日本|JP|🇯🇵
美国|US|🇺🇸"
                      value={editGroup.includePatterns.join('\n')}
                      onChange={(e) => setEditGroup({
                        ...editGroup,
                        includePatterns: e.target.value.split('\n').filter(p => p.trim())
                      })}
                      size="small"
                      sx={styles.textField}
                    />
                  </Box>
                  <Box>
                    <Typography variant="body2" color="text.secondary" gutterBottom>
                      排除节点（黑名单模式）
                    </Typography>
                    <TextField
                      fullWidth
                      multiline
                      rows={3}
                      placeholder="每行一个正则表达式，例如：.*过期.*"
                      value={editGroup.excludePatterns.join('\n')}
                      onChange={(e) => setEditGroup({
                        ...editGroup,
                        excludePatterns: e.target.value.split('\n').filter(p => p.trim())
                      })}
                      size="small"
                      sx={styles.textField}
                    />
                  </Box>
                </Stack>
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button 
            onClick={handleCloseGroupDialog} 
            size="small"
            sx={{
              color: 'text.secondary',
              '&:hover': {
                backgroundColor: 'action.hover',
              },
            }}
          >
            取消
          </Button>
          <Button 
            variant="contained" 
            onClick={handleSaveGroup}
            disabled={loading}
            size="small"
            sx={styles.actionButton}
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>

      {/* Node Dialog */}
      <Dialog
        open={openNodeDialog}
        onClose={handleCloseNodeDialog}
        maxWidth="sm"
        fullWidth
        PaperProps={{
          sx: styles.dialog
        }}
      >
        <DialogTitle>
          {selectedNode ? '编辑节点' : '添加节点'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="节点名称"
                  value={editNode.name}
                  onChange={(e) => setEditNode({ ...editNode, name: e.target.value })}
                  size="small"
                  sx={styles.textField}
                />
              </Grid>
              <Grid item xs={12}>
                <FormControl fullWidth size="small">
                  <InputLabel>节点类型</InputLabel>
                  <Select
                    value={editNode.type}
                    label="节点类型"
                    onChange={(e) => setEditNode({ ...editNode, type: e.target.value })}
                    sx={styles.textField}
                  >
                    <MenuItem value="ss">Shadowsocks</MenuItem>
                    <MenuItem value="ssr">ShadowsocksR</MenuItem>
                    <MenuItem value="vmess">VMess</MenuItem>
                    <MenuItem value="trojan">Trojan</MenuItem>
                  </Select>
                </FormControl>
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="服务器地址"
                  value={editNode.server}
                  onChange={(e) => setEditNode({ ...editNode, server: e.target.value })}
                  size="small"
                  sx={styles.textField}
                />
              </Grid>
              <Grid item xs={12} sm={6}>
                <TextField
                  fullWidth
                  label="端口"
                  type="number"
                  value={editNode.port}
                  onChange={(e) => setEditNode({ ...editNode, port: e.target.value })}
                  size="small"
                  sx={styles.textField}
                />
              </Grid>
              <Grid item xs={12} sm={6}>
                <TextField
                  fullWidth
                  label="密码"
                  value={editNode.password}
                  onChange={(e) => setEditNode({ ...editNode, password: e.target.value })}
                  size="small"
                  type="password"
                  sx={styles.textField}
                />
              </Grid>
              {editNode.type === 'vmess' && (
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="UUID"
                    value={editNode.uuid}
                    onChange={(e) => setEditNode({ ...editNode, uuid: e.target.value })}
                    size="small"
                    sx={styles.textField}
                  />
                </Grid>
              )}
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button
            onClick={handleCloseNodeDialog}
            size="small"
            sx={{
              color: 'text.secondary',
              '&:hover': {
                backgroundColor: 'action.hover',
              },
            }}
          >
            取消
          </Button>
          <Button
            variant="contained"
            onClick={handleSaveNode}
            disabled={loading}
            size="small"
            sx={styles.actionButton}
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>

      {/* Import Dialog */}
      <Dialog
        open={openImportDialog}
        onClose={handleCloseImportDialog}
        maxWidth="sm"
        fullWidth
        PaperProps={{
          sx: styles.dialog
        }}
      >
        <DialogTitle>导入节点</DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="订阅地址"
                  value={importUrl}
                  onChange={(e) => setImportUrl(e.target.value)}
                  size="small"
                  placeholder="输入订阅地址或节点链接"
                  sx={styles.textField}
                />
              </Grid>
              <Grid item xs={12}>
                <FormControlLabel
                  control={
                    <Switch
                      checked={autoUpdate}
                      onChange={(e) => setAutoUpdate(e.target.checked)}
                    />
                  }
                  label="自动更新"
                />
              </Grid>
              {autoUpdate && (
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="更新间隔（小时）"
                    type="number"
                    value={updateInterval}
                    onChange={(e) => setUpdateInterval(e.target.value)}
                    size="small"
                    sx={styles.textField}
                  />
                </Grid>
              )}
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button
            onClick={handleCloseImportDialog}
            size="small"
            sx={{
              color: 'text.secondary',
              '&:hover': {
                backgroundColor: 'action.hover',
              },
            }}
          >
            取消
          </Button>
          <Button
            variant="contained"
            onClick={handleImportNodes}
            disabled={loading}
            size="small"
            sx={styles.actionButton}
          >
            导入
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default Nodes;
